import React, { useState, useEffect, useRef } from 'react';
import { devicesApi } from '../lib/api';

const Terminal = () => {
  const [tabs, setTabs] = useState([]);
  const [activeTab, setActiveTab] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const terminalRef = useRef(null);

  const commands = {
    linux: {
      'ls': { help: 'Listar arquivos', fn: (args) => args.includes('-la') ? 'total 48\ndrwxr-xr-x  5 root root 4096 Feb 15 .\n-rw-r--r--  1 root root  220 .bash_logout\n-rw-r--r--  1 root root 3771 .bashrc' : 'Documents  Downloads  scripts' },
      'pwd': { help: 'Diretorio atual', fn: () => '/root' },
      'whoami': { help: 'Usuario atual', fn: () => 'root' },
      'hostname': { help: 'Nome do host', fn: () => 'server' },
      'date': { help: 'Data e hora', fn: () => new Date().toString() },
      'uptime': { help: 'Tempo de atividade', fn: () => '10:30:00 up 5 days, 12:34, 1 user, load average: 0.15' },
      'free': { help: 'Uso de memoria', fn: (args) => args.includes('-h') ? 'Mem: 7.8Gi used 1.2Gi free 4.5Gi' : 'Mem: 8192000 used 1234567 free 5432109' },
      'df': { help: 'Uso de disco', fn: (args) => args.includes('-h') ? 'Filesystem 98G used 19G avail 75G 21%' : 'Filesystem 51475068K used 8234512K avail 40610472K' },
      'ip': { help: 'Interfaces de rede', fn: (args) => args.includes('a') || args.includes('addr') ? '1: lo: inet 127.0.0.1\n2: eth0: inet 192.168.1.1/24' : 'Use: ip a, ip route' },
      'ifconfig': { help: 'Configuracao de rede', fn: () => 'eth0: inet 192.168.1.1 netmask 255.255.255.0' },
      'ping': { help: 'Testar conexao', fn: (args) => args[0] ? `PING ${args[0]}: 64 bytes ttl=56 time=12ms\n3 packets, 0% loss` : 'Uso: ping <host>' },
      'ps': { help: 'Processos', fn: (args) => args.includes('aux') ? 'USER PID %CPU %MEM COMMAND\nroot 1 0.0 0.1 init' : 'PID TTY TIME CMD' },
      'netstat': { help: 'Conexoes de rede', fn: () => 'tcp 0.0.0.0:22 LISTEN\ntcp 0.0.0.0:80 LISTEN' },
      'cat': { help: 'Mostrar arquivo', fn: (args) => args[0] ? (args[0] === '/etc/passwd' ? 'root:x:0:0:root:/root:/bin/bash' : 'Arquivo nao encontrado') : 'Uso: cat <arquivo>' },
      'clear': { help: 'Limpar tela', fn: 'CLEAR' },
      'exit': { help: 'Fechar terminal', fn: 'EXIT' },
      'help': { help: 'Ajuda', fn: () => 'Comandos: ls, pwd, whoami, hostname, date, uptime, free, df, ip, ifconfig, ping, ps, netstat, cat, clear, exit' },
    },
    mikrotik: {
      '/export': { help: 'Exportar config', fn: () => '# Mikrotik Config\n/interface bridge add name=bridge1\n/ip address add address=192.168.1.1/24' },
      '/system': { help: 'Sistema', fn: () => 'Subcomandos: resource, reboot, identity' },
      '/system resource': { help: 'Recursos', fn: () => 'uptime: 5d12h\nversion: 7.10\ncpu-load: 15%\nfree-memory: 4506MiB' },
      '/interface': { help: 'Interfaces', fn: () => 'Subcomandos: print, enable, disable' },
      '/interface print': { help: 'Listar interfaces', fn: () => 'Flags: R - running\n #   NAME      TYPE\n 0 R ether1    ether\n 1 R ether2    ether' },
      '/ip': { help: 'IP', fn: () => 'Subcomandos: address, route, firewall, dhcp-server' },
      '/ip address print': { help: 'Enderecos IP', fn: () => ' #   ADDRESS         INTERFACE\n 0   192.168.1.1/24  ether1' },
      '/ppp': { help: 'PPP', fn: () => 'Subcomandos: active, secret, profile' },
      '/ppp active print': { help: 'Usuarios PPPoE ativos', fn: () => 'Flags: R - running\n #   NAME    SERVICE  UPTIME\n 0 R user1   pppoe    2d5h\n 1 R user2   pppoe    1d3h\n\nTotal: 2' },
      '/user': { help: 'Usuarios', fn: () => 'Subcomandos: print, add, remove' },
      '/user print': { help: 'Listar usuarios', fn: () => 'Flags: X - disabled\n #   NAME      GROUP\n 0   admin     full\n 1   operator   read' },
    },
    huawei: {
      'display': { help: 'Mostrar informacoes', fn: () => 'Opcoes: version, interface, cpu, memory, arp, ip routing-table, device' },
      'display version': { help: 'Versao do sistema', fn: () => 'Huawei Versatile Routing Platform\nVRP Version 8.231\nNE8000 V800R023C10SPC500' },
      'display interface': { help: 'Interfaces', fn: () => 'Interface              PHY   Protocol\nGigabitEthernet0/0/0   up    up\nGigabitEthernet0/0/1   up    up' },
      'display interface brief': { help: 'Resumo interfaces', fn: () => 'Interface              PHY   Protocol  InUti OutUti\nGigabitEthernet0/0/0   up    up        0.01% 0.01%\nGigabitEthernet0/0/1   up    up        0.02% 0.02%' },
      'display cpu': { help: 'Uso de CPU', fn: () => 'CPU utilization: 15%\nOne minute: 12%\nFive minutes: 10%' },
      'display memory': { help: 'Uso de memoria', fn: () => 'Memory utilization: 45%\nTotal: 8192 MB\nUsed: 3686 MB\nFree: 4506 MB' },
      'display arp': { help: 'Tabela ARP', fn: () => 'IP ADDRESS      MAC ADDRESS     INTERFACE\n192.168.1.1     00-11-22-33-44  GE0/0/0\n192.168.1.2     00-11-22-33-55  GE0/0/0' },
      'display ip routing-table': { help: 'Tabela de rotas', fn: () => 'Destination/Mask    Protocol  NextHop\n0.0.0.0/0          Static    192.168.1.254\n192.168.1.0/24     Direct    0.0.0.0' },
      'display device': { help: 'Informacoes do dispositivo', fn: () => 'Device Status: Normal\nPower Supply: Normal\nFan Status: Normal' },
      'system-view': { help: 'Modo de configuracao', fn: () => 'Enter system view, return user view with Ctrl+Z.' },
      'quit': { help: 'Sair', fn: () => 'EXIT' },
    }
  };

  useEffect(() => { loadDevices(); }, []);

  const loadDevices = async () => {
    try {
      const res = await devicesApi.list();
      setDevices(res || []);
    } catch (e) { console.error(e); }
  };

  const getDeviceType = (vendor) => {
    const v = (vendor || '').toLowerCase();
    if (v.includes('huawei')) return 'huawei';
    if (v.includes('mikrotik')) return 'mikrotik';
    return 'linux';
  };

  const openNewTab = (device) => {
    const existing = tabs.find(t => t.deviceId === device.id);
    if (existing) { setActiveTab(existing.id); setShowDeviceList(false); return; }

    const type = getDeviceType(device.vendor);
    const tab = {
      id: Date.now(),
      deviceId: device.id,
      name: device.hostname,
      ip: device.ip_address,
      port: device.port || 22,
      user: device.username || 'root',
      type: type,
      lines: [],
      history: [],
      histIdx: -1,
      input: '',
      prompt: type === 'huawei' ? '<' + device.hostname + '>' : type === 'mikrotik' ? '[' + device.hostname + '] > ' : device.username + '@' + device.hostname + ':~$ '
    };
    tab.lines.push({ type: 'info', text: `Conectado a ${device.hostname} (${device.ip_address}:${device.port || 22})` });
    tab.lines.push({ type: 'info', text: `Tipo: ${type.toUpperCase()} - Digite "help" para comandos` });
    tab.lines.push({ type: 'info', text: '' });

    setTabs(prev => [...prev, tab]);
    setActiveTab(tab.id);
    setShowDeviceList(false);
  };

  const closeTab = (tabId, e) => {
    if (e) e.stopPropagation();
    setTabs(prev => {
      const n = prev.filter(t => t.id !== tabId);
      if (activeTab === tabId && n.length) setActiveTab(n[n.length - 1].id);
      else if (!n.length) setActiveTab(null);
      return n;
    });
  };

  const autocomplete = (input, type) => {
    const allCmds = { ...commands.linux, ...commands[type] };
    const matches = Object.keys(allCmds).filter(c => c.toLowerCase().startsWith(input.toLowerCase()));
    return matches;
  };

  const execCommand = (tabId, input) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    const cmd = input.trim();
    if (!cmd) return;

    // Add to history
    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, history: [...t.history, cmd], histIdx: -1 } : t));

    // Show command
    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, lines: [...t.lines, { type: 'cmd', text: tab.prompt + cmd }] } : t));

    // Execute
    const parts = cmd.split(' ');
    const cmdName = parts[0].toLowerCase();
    const args = parts.slice(1);
    const fullCmd = cmd.toLowerCase();

    const allCmds = { ...commands.linux, ...commands[tab.type] };
    let result = '';

    if (allCmds[fullCmd]) {
      result = allCmds[fullCmd].fn(args);
    } else if (allCmds[cmdName]) {
      result = allCmds[cmdName].fn(args);
    } else {
      result = `Comando nao encontrado: ${cmdName}\nDigite "help" para ver os comandos disponiveis`;
    }

    if (result === 'CLEAR') {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, lines: [] } : t));
      return;
    }
    if (result === 'EXIT') {
      closeTab(tabId);
      return;
    }

    if (result) {
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, lines: [...t.lines, { type: 'out', text: result }] } : t));
    }
  };

  const handleKeyDown = (e, tabId) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    if (e.key === 'Enter') {
      execCommand(tabId, e.target.value);
      e.target.value = '';
    } else if (e.key === 'Tab') {
      e.preventDefault();
      const input = e.target.value;
      const matches = autocomplete(input, tab.type);
      if (matches.length === 1) {
        e.target.value = matches[0] + ' ';
      } else if (matches.length > 1) {
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, lines: [...t.lines, { type: 'out', text: matches.join('  ') }] } : t));
      }
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (tab.history.length) {
        const idx = tab.histIdx < tab.history.length - 1 ? tab.histIdx + 1 : tab.histIdx;
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, histIdx: idx } : t));
        e.target.value = tab.history[tab.history.length - 1 - idx] || '';
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (tab.histIdx > 0) {
        const idx = tab.histIdx - 1;
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, histIdx: idx } : t));
        e.target.value = tab.history[tab.history.length - 1 - idx] || '';
      } else {
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, histIdx: -1 } : t));
        e.target.value = '';
      }
    } else if (e.ctrlKey && e.key === 'l') {
      e.preventDefault();
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, lines: [] } : t));
    }
  };

  const currentTab = tabs.find(t => t.id === activeTab);

  return (
    <div className="flex flex-col h-[calc(100vh-150px)] bg-black rounded-lg overflow-hidden border border-gray-700">
      {/* Tabs */}
      <div className="flex bg-gray-800 border-b border-gray-700">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map(t => (
            <div key={t.id} onClick={() => setActiveTab(t.id)}
              className={`flex items-center px-4 py-2 cursor-pointer border-r border-gray-700 text-sm ${activeTab === t.id ? 'bg-gray-900 text-white' : 'text-gray-400 hover:bg-gray-700'}`}>
              <span className="w-2 h-2 rounded-full bg-green-500 mr-2" />
              <span>{t.name}</span>
              <span className="ml-2 text-gray-500 text-xs">{t.type}</span>
              <button onClick={(e) => closeTab(t.id, e)} className="ml-3 text-gray-500 hover:text-red-400">x</button>
            </div>
          ))}
        </div>
        <button onClick={() => setShowDeviceList(!showDeviceList)} className="px-4 py-2 text-gray-400 hover:text-white hover:bg-gray-700 text-xl">+</button>
      </div>

      {/* Device list */}
      {showDeviceList && (
        <div className="absolute top-28 right-6 w-72 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-50 max-h-80 overflow-y-auto">
          <div className="p-3 border-b border-gray-700 text-white font-medium">Conectar a:</div>
          <div className="p-2">
            {devices.map(d => (
              <button key={d.id} onClick={() => openNewTab(d)}
                className="w-full p-3 rounded hover:bg-gray-700 text-left flex items-center">
                <span className="w-2 h-2 rounded-full bg-green-500 mr-3" />
                <div>
                  <div className="text-white text-sm">{d.hostname}</div>
                  <div className="text-gray-500 text-xs">{d.ip_address}:{d.port || 22}</div>
                </div>
                <span className="ml-auto text-xs text-gray-500">{d.vendor}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Terminal */}
      {currentTab ? (
        <div ref={terminalRef} className="flex-1 overflow-y-auto p-3 font-mono text-sm bg-black cursor-text" onClick={() => document.getElementById('term-input-' + currentTab.id)?.focus()}>
          {currentTab.lines.map((line, i) => (
            <div key={i} className={`whitespace-pre-wrap leading-relaxed ${line.type === 'cmd' ? 'text-white' : line.type === 'info' ? 'text-cyan-400' : 'text-green-400'}`}>
              {line.text}
            </div>
          ))}
          <div className="flex items-center text-white">
            <span>{currentTab.prompt}</span>
            <input id={'term-input-' + currentTab.id} type="text"
              className="flex-1 bg-transparent outline-none text-white caret-white"
              onKeyDown={(e) => handleKeyDown(e, currentTab.id)}
              autoFocus spellCheck="false" autoComplete="off" />
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-500 bg-black">
          <div className="text-5xl mb-4 font-mono">{'{ }'}</div>
          <div className="text-xl text-white mb-2">Terminal SSH</div>
          <div className="mb-4 text-sm">Suporte: Linux, Mikrotik, Huawei</div>
          <button onClick={() => setShowDeviceList(true)} className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded">Nova Conexao</button>
        </div>
      )}

      {/* Status bar */}
      {currentTab && (
        <div className="flex justify-between px-4 py-1 bg-gray-800 border-t border-gray-700 text-xs text-gray-400">
          <span>{currentTab.ip}:{currentTab.port} | {currentTab.user} | {currentTab.type.toUpperCase()}</span>
          <span>TAB: autocompletar | Ctrl+L: limpar | ↑↓: historico</span>
        </div>
      )}
    </div>
  );
};

export default Terminal;
